1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given an empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a live cell alive when it has 2 live neighbors (survival)", () => {
15	    // Three in a row: center (0,0) has 2 neighbors (-1,0) and (1,0) and survives
16	    const result = nextGeneration([[-1, 0], [0, 0], [1, 0]]);
17	    const keys = new Set(result.map((c) => c.join(",")));
18	    expect(keys.has("0,0")).toBe(true);
19	  });
20	  it("keeps a live cell alive when it has 3 live neighbors (survival)", () => {
21	    // (0,0) has 3 neighbors: (1,0), (0,1), (1,1)
22	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
23	    const keys = new Set(result.map((c) => c.join(",")));
24	    expect(keys.has("0,0")).toBe(true);
25	  });
26	  it("kills a live cell with more than 3 live neighbors (overpopulation)", () => {
27	    // Center (1,1) has 4 live neighbors: (0,0),(1,0),(2,0),(0,2)
28	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2]]);
29	    const keys = new Set(result.map((c) => c.join(",")));
30	    expect(keys.has("1,1")).toBe(false);
31	  });
32	  it("brings a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
33	    // L-shape: (0,0), (1,0), (0,1) → dead cell (1,1) has 3 neighbors
34	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
35	    const keys = new Set(result.map((c) => c.join(",")));
36	    expect(keys.has("1,1")).toBe(true);
37	  });
38	  it("transforms a vertical blinker into a horizontal blinker", () => {
39	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
40	    const result = nextGeneration(vertical);
41	    const keys = new Set(result.map((c) => c.join(",")));
42	    expect(keys).toEqual(new Set(["-1,1", "0,1", "1,1"]));
43	    expect(result.length).toBe(3);
44	  });
45	  it("keeps a block (still life) unchanged", () => {
46	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
47	    const result = nextGeneration(block);
48	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
49	      new Set(block.map((c) => c.join(",")))
50	    );
51	    expect(result.length).toBe(4);
52	  });
53	  it("handles negative coordinates correctly", () => {
54	    // Block at negative coordinates - should be unchanged (still life)
55	    const block: [number, number][] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
56	    const result = nextGeneration(block);
57	    const keys = new Set(result.map((c) => c.join(",")));
58	    expect(keys).toEqual(new Set(block.map((c) => c.join(","))));
59	    expect(result.length).toBe(4);
60	  });
61	});
